{"code": "import json
import os

# Load the books data with publication years
books_file = 'var_functions.query_db:18'
books = locals().get(books_file)

# If it's a file path, read it
if isinstance(books, str) and books.endswith('.json'):
    with open(books, 'r') as f:
        books = json.load(f)

# Process the books data
books_with_years = []
for book in books:
    book_id = book.get('book_id')
    publication_year = book.get('publication_year')
    if book_id and publication_year:
        books_with_years.append({
            'book_id': book_id,
            'publication_year': int(publication_year) if publication_year else None
        })

print('__RESULT__:')
print(json.dumps({
    "total_books_with_years": len(books_with_years),
    "sample_books": books_with_years[:5]
}))"}

